detaileddescription.para:
Setters return a reference to this object to support fluent method chaining: intmain(intargc,char**argv)
{
Applicationapplication=Application::New(&argc,&argv);

UiConfig::New()
.SetScalingFactor(1.5f)
.SetDpi(320)
.Apply();

HelloWorldControllertest(application);
application.MainLoop();

return0;
}
